9	// reportedWorkersAdapter adapts the in-memory worker_ingest registry to the
10	// ddxgraphql.ReportedWorkersProvider interface used by the reportedWorkers
11	// query. now is overridable so tests can advance the freshness clock without
12	// mutating registry timestamps.
13	type reportedWorkersAdapter struct {
14		reg *workerIngestRegistry
15		now func() time.Time
16	}
17	
18	func newReportedWorkersAdapter(reg *workerIngestRegistry) *reportedWorkersAdapter {
19		return &reportedWorkersAdapter{reg: reg, now: func() time.Time { return time.Now().UTC() }}
20	}
21	
22	// GetReportedWorkers implements ddxgraphql.ReportedWorkersProvider.
23	func (a *reportedWorkersAdapter) GetReportedWorkers() []*ddxgraphql.ReportedWorker {
24		if a.reg == nil {
25			return nil
26		}
27		now := a.now()
28		snap := a.reg.snapshot()
29		out := make([]*ddxgraphql.ReportedWorker, 0, len(snap))
30		for _, rec := range snap {
31			w := &ddxgraphql.ReportedWorker{
32				ID:                  rec.WorkerID,
33				Project:             rec.Identity.ProjectRoot,
34				Harness:             rec.Identity.Harness,
35				State:               freshnessState(rec, now),
36				LastEventAt:         rec.LastEventAt.UTC().Format(time.RFC3339Nano),
37				MirrorFailuresCount: rec.MirrorFailuresCount,
38				HadDroppedBackfill:  rec.HadDroppedBackfill,
39			}
40			if rec.CurrentBead != "" {
41				cb := rec.CurrentBead
42				w.CurrentBead = &cb
43			}
44			if rec.CurrentAttempt != "" {
45				ca := rec.CurrentAttempt
46				w.CurrentAttempt = &ca
47			}
48			out = append(out, w)
49		}
50		return out
51	}
