39	// newReportedWorkersHandler builds a GraphQL handler whose reportedWorkers
40	// resolver reads from reg, with now overridable so tests can advance the
41	// freshness clock without juggling LastEventAt timestamps.
42	func newReportedWorkersHandler(reg *workerIngestRegistry, now func() time.Time) http.Handler {
43		gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
44			Resolvers: &ddxgraphql.Resolver{
45				State:           &emptyStateProvider{},
46				WorkingDir:      "/tmp/ignored",
47				ReportedWorkers: &reportedWorkersAdapter{reg: reg, now: now},
48			},
49			Directives: ddxgraphql.DirectiveRoot{},
50		}))
51		gqlSrv.AddTransport(transport.POST{})
52		return gqlSrv
53	}
