77	// TestGraphQL_Workers_FreshnessFields exercises the connected/stale/disconnected
78	// transitions by holding LastEventAt fixed and advancing the resolver's clock
79	// past the rev-5 freshness thresholds (probe interval = 30s).
80	func TestGraphQL_Workers_FreshnessFields(t *testing.T) {
81		t.Parallel()
82	
83		reg := newWorkerIngestRegistry(t.TempDir())
84		t.Cleanup(func() { _ = reg.close() })
85	
86		rec := reg.register(workerIdentity{
87			ProjectRoot: "/proj/alpha",
88			Harness:     "claude",
89			StartedAt:   time.Now().UTC(),
90		})
91		// Drive recordEvent so currentBead/currentAttempt are populated and
92		// LastEventAt is set to a fixed reference instant.
93		if err := reg.recordEvent(rec.WorkerID, workerEvent{
94			BeadID:    "bead-1",
95			AttemptID: "attempt-1",
96			Kind:      "phase",
97		}); err != nil {
98			t.Fatalf("recordEvent: %v", err)
99		}
100	
101		// Pin LastEventAt so the resolver's clock cleanly drives the transition.
102		reference := time.Now().UTC()
103		reg.mu.Lock()
104		reg.workers[rec.WorkerID].LastEventAt = reference
105		reg.mu.Unlock()
106	
107		cases := []struct {
108			name  string
109			now   time.Time
110			state string
111		}{
112			// Probe interval is 30s; connected ≤ 60s, stale ≤ 300s, disconnected else.
113			{"connected", reference.Add(10 * time.Second), "connected"},
114			{"stale", reference.Add(2 * time.Minute), "stale"},
115			{"disconnected", reference.Add(20 * time.Minute), "disconnected"},
116		}
117		for _, tc := range cases {
118			tc := tc
119			t.Run(tc.name, func(t *testing.T) {
120				now := tc.now
121				h := newReportedWorkersHandler(reg, func() time.Time { return now })
122				resp := postReportedWorkers(t, h)
123				if got := len(resp.Data.ReportedWorkers); got != 1 {
124					t.Fatalf("want 1 reported worker, got %d", got)
125				}
126				w := resp.Data.ReportedWorkers[0]
127				if w.State != tc.state {
128					t.Fatalf("state: want %q, got %q", tc.state, w.State)
129				}
130				if w.ID != rec.WorkerID {
131					t.Fatalf("id: want %q, got %q", rec.WorkerID, w.ID)
132				}
133				if w.Project != "/proj/alpha" {
134					t.Fatalf("project: want /proj/alpha, got %q", w.Project)
135				}
136				if w.Harness != "claude" {
137					t.Fatalf("harness: want claude, got %q", w.Harness)
138				}
139				if w.CurrentBead == nil || *w.CurrentBead != "bead-1" {
140					t.Fatalf("currentBead: want bead-1, got %v", w.CurrentBead)
141				}
142				if w.CurrentAttempt == nil || *w.CurrentAttempt != "attempt-1" {
143					t.Fatalf("currentAttempt: want attempt-1, got %v", w.CurrentAttempt)
144				}
145			})
146		}
147	}
