149	// TestGraphQL_Workers_MultipleWorkersPerProject verifies that two workers
150	// reporting under the same project_root both surface in the derived view —
151	// the duplicate-worker visibility ADR-022 promises operators.
152	func TestGraphQL_Workers_MultipleWorkersPerProject(t *testing.T) {
153		t.Parallel()
154	
155		reg := newWorkerIngestRegistry(t.TempDir())
156		t.Cleanup(func() { _ = reg.close() })
157	
158		const project = "/proj/beta"
159		rec1 := reg.register(workerIdentity{ProjectRoot: project, Harness: "claude"})
160		rec2 := reg.register(workerIdentity{ProjectRoot: project, Harness: "codex"})
161		if rec1.WorkerID == rec2.WorkerID {
162			t.Fatalf("expected distinct worker_ids, got %q == %q", rec1.WorkerID, rec2.WorkerID)
163		}
164	
165		now := time.Now().UTC()
166		h := newReportedWorkersHandler(reg, func() time.Time { return now })
167		resp := postReportedWorkers(t, h)
168		if got := len(resp.Data.ReportedWorkers); got != 2 {
169			t.Fatalf("want 2 reported workers, got %d", got)
170		}
171		seen := map[string]string{}
172		for _, w := range resp.Data.ReportedWorkers {
173			if w.Project != project {
174				t.Fatalf("project: want %q, got %q", project, w.Project)
175			}
176			seen[w.ID] = w.Harness
177		}
178		if seen[rec1.WorkerID] != "claude" {
179			t.Fatalf("worker1 harness: want claude, got %q", seen[rec1.WorkerID])
180		}
181		if seen[rec2.WorkerID] != "codex" {
182			t.Fatalf("worker2 harness: want codex, got %q", seen[rec2.WorkerID])
183		}
184	}
