19	// postLoopback sends a JSON POST to path with body and returns the recorder.
20	// Sets the loopback RemoteAddr so the requireTrusted gate passes.
21	func postLoopback(t *testing.T, srv *Server, path string, body any) *httptest.ResponseRecorder {
22		t.Helper()
23		var buf bytes.Buffer
24		if body != nil {
25			if err := json.NewEncoder(&buf).Encode(body); err != nil {
26				t.Fatalf("encode body: %v", err)
27			}
28		}
29		req := httptest.NewRequest(http.MethodPost, path, &buf)
30		req.Header.Set("Content-Type", "application/json")
31		req.RemoteAddr = "127.0.0.1:54321"
32		w := httptest.NewRecorder()
33		srv.Handler().ServeHTTP(w, req)
34		return w
35	}
